$endash = [char]0x2013
$lookup[("Stock Buy and Sell " + $endash + " Max 2 Transactions Allowed")] = @("DP with states: before first buy, holding first, after first sell, holding second, after second sell.", "", "O(n)", "O(1)")
$lookup[("Stock Buy and Sell " + $endash + " Max K Transactions Allowed")] = @("DP. dp[k][i] = max profit with at most k transactions up to day i.", "", "O(k*n)", "O(k*n)")
$lookup[("Stock Buy and Sell " + $endash + " Max one Transaction Allowed")] = @("Track minimum price seen so far; at each day, max profit = price - minPrice. Update max profit.", "", "O(n)", "O(1)")
$lookup[("Stock Buy and Sell " + $endash + " Multiple Transaction Allowed")] = @("Greedy. Sum all positive consecutive differences (buy every valley, sell every peak).", "", "O(n)", "O(1)")

$gfgDir = "gfg-solutions"
$files = Get-ChildItem $gfgDir -Recurse -Filter *.java | Where-Object {
  -not (Select-String -Path $_.FullName -Pattern "//\s*Approach:" -Quiet)
}

$count = 0
$skipped = 0

foreach ($file in $files) {
  $name = [System.IO.Path]::GetFileNameWithoutExtension($file.Name)
  
  if ($lookup.ContainsKey($name)) {
    $entry   = $lookup[$name]
    $line1   = $entry[0]
    $line2   = $entry[1]
    $time    = $entry[2]
    $space   = $entry[3]

    $existing = [System.IO.File]::ReadAllText($file.FullName)
    
    if ($line2 -and $line2 -ne "") {
      $header = "// Approach: $line1`r`n// $line2`r`n// Time: $time Space: $space`r`n"
    } else {
      $header = "// Approach: $line1`r`n// Time: $time Space: $space`r`n"
    }
    
    $newContent = $header + $existing
    [System.IO.File]::WriteAllText($file.FullName, $newContent, [System.Text.Encoding]::UTF8)
    $count++
  } else {
    Write-Host "SKIPPED (not in lookup): $name"
    $skipped++
  }
}

Write-Host "`nDone. Updated: $count files. Skipped: $skipped files."
